main_container.script:
document.addEventListener('DOMContentLoaded', () => {
    const searchInput = document.getElementById('project-search');
    const categoryTabs = document.querySelectorAll('.category-tab');
    const projectSections = document.querySelectorAll('.projects-section');
    const allCards = document.querySelectorAll('.card-project, .card-project-hero');

    function filterProjects() {
        const searchTerm = searchInput.value.toLowerCase();
        const activeTab = document.querySelector('.category-tab.active');
        if (!activeTab) return;

        const activeFilter = activeTab.dataset.filter;

        // Filter sections based on category
        projectSections.forEach(section => {
            const sectionFilter = section.dataset.sectionFilter;
            // If filter is 'all', show all sections
            // Otherwise, only show 'all' sections OR the specific category section
            if (activeFilter === 'all' || sectionFilter === 'all' || sectionFilter === activeFilter) {
                section.style.display = 'flex';
            } else {
                section.style.display = 'none';
            }
        });

        // Filter individual cards within visible sections (for search)
        allCards.forEach(card => {
            const nameEn = card.getAttribute('data-translation_en') || '';
            const nameFr = card.getAttribute('data-translation_fr') || '';
            const matchesSearch = nameEn.toLowerCase().includes(searchTerm) || nameFr.toLowerCase().includes(searchTerm);

            if (matchesSearch) {
                card.classList.remove('project-hidden');
            } else {
                card.classList.add('project-hidden');
            }
        });
    }

    searchInput.addEventListener('input', filterProjects);

    categoryTabs.forEach(tab => {
        tab.addEventListener('click', () => {
            categoryTabs.forEach(t => t.classList.remove('active'));
            tab.classList.add('active');
            filterProjects();
        });
    });

    // Initial run
    filterProjects();
});
